3_real_world_example.code:
const stats = {
  strength: 10,
  agility: 15,
  magic: 5
};

// Dot notation (Hardcoded)
console.log(stats.strength); // 10

function printStat(statName) {
  //  BAD: This looks for a literal property called 'statName'
  console.log(stats.statName); // undefined

  //  GOOD: Evaluates the variable first, then looks up the string
  console.log(stats[statName]);
}

printStat('agility'); // 15

